let audioCtx=null,musicRunning=false,musicGen=0,musicTid=null;
function initAudio(){
  try{audioCtx=new(window.AudioContext||window.webkitAudioContext)();}catch(e){}
}
document.addEventListener('click',()=>{if(audioCtx&&audioCtx.state==='suspended')audioCtx.resume();},{once:true});

function noteAbs(f,absT,dur,vol,type){
  // Schedule at an absolute Web Audio time (used by MIDI scheduler)
  if(!audioCtx||!f||absT===undefined)return;
  vol=vol||0.08; type=type||'square';
  var o=audioCtx.createOscillator(),g=audioCtx.createGain();
  o.connect(g); g.connect(audioCtx.destination);
  o.type=type; o.frequency.value=f;
  g.gain.setValueAtTime(0,absT);
  g.gain.linearRampToValueAtTime(vol,absT+0.012);
  g.gain.setValueAtTime(vol,absT+dur*0.7);
  g.gain.linearRampToValueAtTime(0,absT+dur);
  o.start(absT); o.stop(absT+dur+0.05);
}
function note(f,st,dur,vol,type){
  // Schedule relative to now (used by SFX: st=0, 0.1, 0.2...)
  if(!audioCtx||!f)return;
  noteAbs(f, audioCtx.currentTime+st, dur, vol, type);
}

