// Lookahead scheduler — schedules only ~300ms ahead at a time
// This avoids blocking the JS thread with 868 simultaneous AudioNode creations
var _schedIdx=0, _schedLoopStart=0, _schedInterval=null;
var LOOKAHEAD=0.3;  // seconds ahead to schedule
var TICK_MS=100;    // how often to run scheduler

function _schedTick(){
  if(!audioCtx||!musicRunning)return;
  var now=audioCtx.currentTime;
  var schedUntil=now+LOOKAHEAD;
  var n=MIDI_NOTES, len=n.length;

  // Schedule notes whose absolute time falls within our lookahead window
  while(_schedIdx<len){
    var noteAbsTime=_schedLoopStart+n[_schedIdx];
    if(noteAbsTime>schedUntil) break;
    if(noteAbsTime>=now-0.05){  // skip notes already in the past
      noteAbs(n[_schedIdx+2], noteAbsTime, n[_schedIdx+1], n[_schedIdx+3], MIDI_WAVES[n[_schedIdx+4]]);
    }
    _schedIdx+=5;
  }

  // If we've reached the end of the loop, queue the next iteration
  if(_schedIdx>=len){
    _schedLoopStart+=MIDI_LOOP_DUR;
    _schedIdx=0;
  }
}

function playMusic(){
  if(!audioCtx||musicRunning)return;
  musicRunning=true; musicGen++;
  var gen=musicGen;
  _schedIdx=0;
  _schedLoopStart=audioCtx.currentTime;
  if(_schedInterval) clearInterval(_schedInterval);
  _schedInterval=setInterval(function(){
    if(!musicRunning||musicGen!==gen){clearInterval(_schedInterval);_schedInterval=null;return;}
    _schedTick();
  },TICK_MS);
  _schedTick(); // prime immediately
}

function stopMusic(){
  musicRunning=false; musicGen++;
  if(_schedInterval){clearInterval(_schedInterval);_schedInterval=null;}
  if(musicTid){clearTimeout(musicTid);musicTid=null;}
}

